B.a1H=new A.ab(-21,B.ai,252,"What is the function of the rudder?",B.RB,2,B.L,null,null,null)
B.TT=s(["The fuselage section","The engine housing","The cockpit area","The cargo hold"],t.s)
B.a1h=new A.ab(-22,B.ai,253,'The "nacelle" refers to which part of the aircraft?',B.TT,1,B.A,null,null,null)
