B.PJ=new A.T(B.ac,"ATC phraseology is standardized","Air Traffic Control communications follow ICAO standard phraseology. Fill-in-the-blank questions test whether you know the **exact words** used in clearances, instructions, and readbacks.\n\nThe key is understanding the **structure** of each phrase type so you can identify the missing word even without memorizing every phrase.",null,null,null)
B.QS=new A.T(B.B,"\ud83d\udeeb Clearance Structure",'A standard ATC clearance follows this pattern:\n\n**Aircraft ID** + clearance limit + route + altitude + speed + squawk\n\nExample: "THY123, **cleared to** Istanbul, via KEMER, **climb and maintain** FL350, squawk 4521."\n\nKey verbs: **cleared**, **maintain**, **climb**, **descend**, **turn**, **contact**, **report**',null,null,null)
B.OJ=new A.T(B.B,"\ud83d\udcfb Readback Rules",'Pilots must **read back** all:\n\u2022 Runway in use\n\u2022 Altimeter settings\n\u2022 Altitude/flight level\n\u2022 Heading instructions\n\u2022 Speed instructions\n\u2022 Frequency changes\n\u2022 Transponder codes\n\u2022 Taxi instructions (at controlled airports)\n\n**Standard phrase:** "Cleared to FL350, THY123." (call sign at end in readback)',null,null,null)
B.Kv=new A.aE(u.G,"THY123, al\xe7al ve u\xe7u\u015f seviyesi 150'yi koru.","descend and maintain")
B.L1=new A.aE("Cleared for ILS approach runway 36R, report established.","\u0130LS yakla\u015f\u0131m\u0131 pist 36R i\xe7in yetkilendirildiniz, ini\u015f glide slope'unda oldu\u011funuzda bildirin.","report established")
B.Lb=new A.aE("Hold short of runway 18L, traffic on final.","Pist 18L'ye girmeden bekleyin, finalden gelen trafik var.","Hold short")
B.V_=s([B.Kv,B.L1,B.Lb],t.l)
B.Ok=new A.T(B.ad,"Phraseology Examples",null,B.V_,null,null)
B.Ra=new A.T(B.ae,"\u2708\ufe0f Exam Strategy",'For fill-in-the-blank ATC questions:\n1. Read the **whole sentence** first \u2014 understand the situation\n2. Identify the **verb type** needed (is it a clearance, instruction, or report?)\n3. Use **elimination** \u2014 remove grammatically wrong options first\n4. Check for **prepositions**: "cleared **to**", "cleared **for**", "climb **to**", "maintain **at**"',null,null,null)
B.Si=s(["cleared to land","cleared for landing","cleared landing","clear to land"],t.s)
