B.Ou=new A.T(B.ac,"Conditionals describe cause and effect","Aviation procedures often describe what happens **if** a certain condition occurs. Emergency checklists, operational manuals, and exam questions rely heavily on conditional sentences.\n\nUnderstanding which conditional type to use depends on whether the situation is **real/possible** or **hypothetical/impossible**.",null,null,null)
B.Qq=new A.T(B.eU,"Conditional types at a glance",null,null,B.qH,null)
B.Ox=new A.T(B.B,"The Three Main Types",'**Type 1 \u2014 Real/Possible (present/future)**\nIf + present simple, will/can/must + base verb\n\u2192 "If the oil pressure drops, the pilot **will** declare an emergency."\n\n**Type 2 \u2014 Hypothetical (present/future)**\nIf + past simple, would/could + base verb\n\u2192 "If the engine **failed**, the crew **would** follow the ECAM."\n\n**Type 3 \u2014 Impossible (past)**\nIf + past perfect, would/could + have + past participle\n\u2192 "If the crew **had noticed** the leak, they **would have** diverted."',null,null,null)
B.JY=new A.aE("If the fuel quantity drops below minimum, the aircraft must return to base.","Yak\u0131t miktar\u0131 minimumun alt\u0131na d\xfc\u015ferse u\xe7ak \xfcsse d\xf6nmelidir.","If the fuel quantity drops")
B.KW=new A.aE("If the hydraulic system were to fail, the pilot would use backup controls.","Hidrolik sistem ar\u0131za yapsa pilot yedek kontrolleri kullan\u0131rd\u0131.","were to fail")
B.JV=new A.aE("If maintenance had been performed on time, the fault would not have occurred.","Bak\u0131m zaman\u0131nda yap\u0131lsayd\u0131 ar\u0131za meydana gelmezdi.","had been performed")
B.Ws=s([B.JY,B.KW,B.JV],t.l)
B.Qb=new A.T(B.ad,"Aviation Conditionals",null,B.Ws,null,null)
B.QZ=new A.T(B.ae,"\u2708\ufe0f Exam Tip",'Quick identification trick:\n\u2022 See "will" in the result clause \u2192 **Type 1** (real)\n\u2022 See "would" + present base \u2192 **Type 2** (hypothetical)\n\u2022 See "would have" + past participle \u2192 **Type 3** (past)\n\nWatch for "unless" = "if not":\n"Unless the checklist is completed, departure is not permitted."\n= "If the checklist is **not** completed, departure is not permitted."',null,null,null)
B.VS=s(["will drop","drops","dropped","would drop"],t.s)
B.a24=new A.ab(-40,B.ah,100,"If the oil pressure \u2026\u2026\u2026\u2026 below the minimum, the pilot must shut down the engine.",B.VS,1,B.A,null,null,null)
B.V6=s(["could be","could have been","can be","will be"],t.s)
B.a31=new A.ab(-41,B.ah,101,"If the de-icing system had been activated earlier, the accident \u2026\u2026\u2026\u2026 avoided.",B.V6,1,B.A,null,null,null)
B.Xa=s(["are","were","will be","have been"],t.s)
B.a2L=new A.ab(-42,B.ah,102,"Unless all systems \u2026\u2026\u2026\u2026 serviceable, the aircraft should not depart.",B.Xa,0,B.aY,null,null,null)
B.WD=s(["is","was","would be","were"],t.s)
B.a2M=new A.ab(-43,B.ah,103,"If the runway \u2026\u2026\u2026\u2026 contaminated, takeoff performance must be recalculated.",B.WD,0,B.A,null,null,null)
B.RZ=s([B.a24,B.a31,B.a2L,B.a2M],t.C)
