B.Pj=new A.T(B.ac,"Modern aircraft rely on complex instrument systems","Avionics vocabulary appears in reading comprehension, vocabulary fill-in, and sentence completion questions. Understanding what each instrument does and how it is described in manuals is essential for intermediate and advanced levels.",null,null,null)
B.Rb=new A.T(B.B,"\u2708\ufe0f Primary Flight Instruments","**ADI (Attitude Director Indicator)** \u2014 shows pitch and bank\n**HSI (Horizontal Situation Indicator)** \u2014 combined heading + navigation\n**VSI (Vertical Speed Indicator)** \u2014 rate of climb/descent in feet per minute\n**ASI (Airspeed Indicator)** \u2014 shows IAS in knots\n**Altimeter** \u2014 shows altitude using static pressure\n**Turn & Slip Indicator** \u2014 shows rate of turn and coordination",null,null,null)
B.QQ=new A.T(B.B,"\ud83d\udef0\ufe0f Navigation Systems","**FMS (Flight Management System)** \u2014 computerized navigation, flight planning, and performance\n**GPS (Global Positioning System)** \u2014 satellite-based positioning\n**IRS/INS (Inertial Reference System)** \u2014 self-contained navigation using accelerometers\n**DME (Distance Measuring Equipment)** \u2014 ground-based range measurement\n**ADF (Automatic Direction Finder)** \u2014 homes to NDB stations\n**TCAS II** \u2014 provides Resolution Advisories (RA) to avoid traffic",null,null,null)
B.JQ=new A.aE("The FMS automatically calculates the most fuel-efficient cruise altitude.","FMS, en yak\u0131t verimli seyir irtifas\u0131n\u0131 otomatik olarak hesaplar.","FMS")
