B.NV=new A.cp("vocab_7","Expert ICAO Vocabulary","vocabulary","\ud83c\udfc6",B.Tk)
B.Qu=new A.T(B.ac,"Procedure documents are dense with technical information","Standard Instrument Departures (SIDs) and Standard Terminal Arrival Routes (STARs) are documented procedures that contain altitudes, speeds, waypoints, and restrictions. Advanced reading questions use extracts from these documents and require precise interpretation.",null,null,null)
B.P6=new A.T(B.B,"\ud83d\udeeb SID \u2014 Departure Procedure",'A SID (Standard Instrument Departure) provides:\n\u2022 Routing from runway to en-route structure\n\u2022 Altitude restrictions ("at or above 3,000 ft at waypoint TURPO")\n\u2022 Speed restrictions ("250 KIAS below 10,000 ft")\n\u2022 Transition codes (RNAV, conventional)\n\n**Altitude coding:**\n\u2022 **"A030+"** = at or above 3,000 ft\n\u2022 **"A050-"** = at or below 5,000 ft\n\u2022 **"A060B080"** = between 6,000 and 8,000 ft\n\u2022 **"S220"** = maintain speed 220 KIAS or below',null,null,null)
B.OV=new A.T(B.B,"\ud83d\udeec STAR \u2014 Arrival Procedure",'A STAR (Standard Terminal Arrival Route) provides:\n\u2022 Routing from en-route to terminal area / approach\n\u2022 Speed reduction profile\n\u2022 Transition to IAF (Initial Approach Fix)\n\n**Common STAR terminology:**\n\u2022 **IAF** \u2014 Initial Approach Fix (start of approach)\n\u2022 **IF** \u2014 Intermediate Fix\n\u2022 **FAF** \u2014 Final Approach Fix\n\u2022 **MAP** \u2014 Missed Approach Point\n\u2022 **Published hold** \u2014 holding pattern on procedure\n\u2022 **"Expect vectors"** \u2014 ATC will give radar headings instead',null,null,null)
B.KS=new A.aE("At or above 6,000 feet at TURPO waypoint before turning left to intercept the final approach course.","Final yakla\u015fma pistine girilmeden \xf6nce TURPO noktas\u0131nda 6.000 ft veya \xfczerinde olmak zorunludur.","At or above")
B.KE=new A.aE("Maintain 250 knots or less until 10 DME from the airport.","Havaliman\u0131ndan 10 DME mesafeye kadar 250 knot veya daha d\xfc\u015f\xfck h\u0131z koruyun.","Maintain 250 knots or less")
B.U1=s([B.KS,B.KE],t.l)
B.Pf=new A.T(B.ad,"Procedure Language",null,B.U1,null,null)
B.OX=new A.T(B.ae,"\u2708\ufe0f Exam Tip",'"At or above" / "at or below" in procedure documents:\n\u2022 "A030+" = at or **above** 3,000 ft (plus sign = higher)\n\u2022 "A050-" = at or **below** 5,000 ft (minus sign = lower)\n\nIf you see both a speed and altitude restriction at a waypoint, **both** must be complied with simultaneously.\n\n"Expect vectors" on a STAR does not mean ATC will always give vectors \u2014 it means the pilot should expect them (but must fly the published procedure if not given vectors).',null,null,null)
B.Uj=s(["At 4,000 ft exactly","At or above 4,000 ft","At or below 4,000 ft","Between 4,000 and 4,500 ft"],t.s)
B.a2D=new A.ab(-270,B.av,640,'In a SID procedure document, "A040+" means the aircraft must be:',B.Uj,1,B.A,null,null,null)
B.SY=s(["The beginning of the missed approach","The start of the final approach segment","The runway threshold","The IAF position"],t.s)
B.a2R=new A.ab(-271,B.av,641,"The FAF (Final Approach Fix) marks:",B.SY,1,B.A,null,null,null)
B.X1=s(["Vectors will definitely be given by ATC","The pilot should anticipate radar vectors but fly published procedure if not given","Vectors are not available on this route","The pilot may request vectors"],t.s)
B.a21=new A.ab(-272,B.av,642,'"Expect vectors" on a STAR means:',B.X1,1,B.aY,null,null,null)
B.Th=s(["Climb to speed 220 knots","Maintain 220 KIAS or less","Set Mach 0.220","Not exceed 220 feet per minute climb"],t.s)
B.a1y=new A.ab(-273,B.av,643,'If a SID shows "S220" at a waypoint, the crew must:',B.Th,1,B.aY,null,null,null)
B.Uw=s([B.a2D,B.a2R,B.a21,B.a1y],t.C)
B.PK=new A.T(B.a4,"Practice Questions",null,null,null,B.Uw)
B.Tb=s([B.Qu,B.P6,B.OV,B.Pf,B.OX,B.PK],t.q)
B.Oa=new A.cp("reading_5","SID/STAR Procedures","reading","\ud83d\uddfa\ufe0f",B.Tb)
B.Q2=new A.T(B.ac,"Accident reports are complex texts","Aviation accident investigation reports (such as those produced by ICAO Annex 13 standards) are among the most complex texts tested in aviation English exams.\n\nThey contain technical terminology, passive constructions, reported speech, and conditional reasoning \u2014 all combined in a single document.",null,null,null)
B.QK=new A.T(B.B,"\ud83d\udccb Report Structure","A standard accident report contains:\n1. **Synopsis** \u2014 brief summary of the accident\n2. **Factual information** \u2014 aircraft, crew, weather, airport data\n3. **Analysis** \u2014 what happened and why (cause chain)\n4. **Findings** \u2014 established facts\n5. **Cause** \u2014 probable cause(s)\n6. **Safety recommendations** \u2014 what should change\n\nExam questions usually target **Factual Information** and **Analysis** sections.",null,null,null)
B.QN=new A.T(B.B,"\ud83d\udd0d Critical Reading Skills","For accident report passages:\n\u2022 **Sequence words**: prior to, during, following, subsequently, as a result\n\u2022 **Causal language**: due to, caused by, attributed to, led to, resulted in\n\u2022 **Finding vs. Recommendation**: findings are facts; recommendations are suggestions\n\u2022 **Contributing factor** \u2260 **Probable cause**: contributing factors worsen the situation; probable cause is the primary reason",null,null,null)
B.K2=new A.aE("The accident was attributed to the crew's failure to monitor fuel quantity during the extended hold.","Kaza, ekibin uzun s\xfcren bekleme s\u0131ras\u0131nda yak\u0131t miktar\u0131n\u0131 izlememesine ba\u011fland\u0131.","attributed to")
B.Ky=new A.aE("A contributing factor was the inadequate crew resource management training.","Katk\u0131da bulunan bir fakt\xf6r yetersiz ekip kaynak y\xf6netimi e\u011fitimiydi.","contributing factor")
B.SM=s([B.K2,B.Ky],t.l)
B.P2=new A.T(B.ad,"Report Language Examples",null,B.SM,null,null)
B.Pt=new A.T(B.ae,"\u2708\ufe0f Advanced Reading Strategy","The 3-read method for complex passages:\n1. **First read**: skim for topic and structure (30 seconds)\n2. **Read question**: understand exactly what is asked\n3. **Second read**: focus on the relevant paragraph only\n\nNever answer from memory \u2014 always verify in the text. Advanced questions often have **plausible but incorrect** distractors that use words from the passage in the wrong context.",null,null,null)
B.T_=s(["To start the engine for the first time","To test the fuel system","To increase engine speed","To test the electrical system"],t.s)
B.a2Z=new A.ab(-100,B.av,606,"What is the purpose of wet motoring the engine?",B.T_,1,B.L,null,null,null)
