B.a2q=new A.ab(-101,B.av,607,"During wet motoring, what is the position of the ignition systems?",B.Sn,2,B.L,null,null,null)
B.U7=s(["Engine speed only","The starter motor temperature","The exhaust nozzle for signs of fuel","The HP rotor vibration"],t.s)
