B.OR=new A.T(B.ac,"Accident reports use precise legal and technical language","ICAO Annex 13 accident investigation reports are among the most linguistically demanding documents in aviation. They combine legal precision, passive constructions, technical accuracy, and causal analysis in a single text.\n\nTranslation questions from these reports require understanding both the technical meaning and the legal implications of each phrase.",null,null,null)
B.Qf=new A.T(B.B,"\u26a0\ufe0f Causal Language",'**Probable cause** \u2014 the primary factor judged to have produced the accident\n**Contributing factor** \u2014 a condition that increased risk but was not the primary cause\n**Causal factor** \u2014 any element in the cause chain\n\nCausal verbs and phrases:\n\u2022 "**led to**" = caused/resulted in (direct chain)\n\u2022 "**attributed to**" = judged as the cause\n\u2022 "**resulted in**" = produced this outcome\n\u2022 "**was a factor in**" = contributed but not sole cause\n\u2022 "**was consistent with**" = evidence matches this explanation',null,null,null)
B.PW=new A.T(B.B,"\ud83d\udccb Investigation Findings Language",'"The investigation **found** that\u2026" \u2192 formal finding\n"Evidence **indicated** that\u2026" \u2192 supported but not proven\n"**It could not be determined** whether\u2026" \u2192 insufficient evidence\n"The crew **failed to**\u2026" \u2192 did not perform required action\n"**Contrary to** the standard operating procedure\u2026" \u2192 SOP violation\n"The accident **is survivable** / **was not survivable**" \u2192 survivability finding\n"**Safety recommendation**" \u2192 formal advisory to prevent recurrence',null,null,null)
B.L9=new A.aE("The probable cause of the accident was the crew's failure to monitor fuel quantity.","Kazan\u0131n muhtemel nedeni, ekibin yak\u0131t miktar\u0131n\u0131 izlememesiydi.","probable cause")
B.KK=new A.aE("It could not be determined whether the crew had received the updated weather information.","Ekibin g\xfcncellenmi\u015f hava durumu bilgisini al\u0131p almad\u0131\u011f\u0131 belirlenemedi.","It could not be determined")
B.L7=new A.aE("The investigation attributed the loss of situational awareness to crew fatigue and inadequate CRM.","Soru\u015fturma, durum fark\u0131ndal\u0131\u011f\u0131n\u0131n kayb\u0131n\u0131 m\xfcrettebat yorgunlu\u011funa ve yetersiz EKY'ye ba\u011flad\u0131.","attributed to")
B.Xs=s([B.L9,B.KK,B.L7],t.l)
B.Pk=new A.T(B.ad,"Report Passage Examples",null,B.Xs,null,null)
B.Qt=new A.T(B.ae,"\u2708\ufe0f Translation Exam Strategy",'For accident report translation questions:\n\u2022 "**Probable cause**" \u2260 "possible cause" \u2014 it is the MOST LIKELY established cause\n\u2022 "**Contributing factor**" \u2260 "main reason" \u2014 it is a secondary, exacerbating condition\n\u2022 "**Crew failed to**" = they did not do something required \u2014 not necessarily negligence\n\u2022 "**It could not be determined**" = insufficient evidence \u2014 do NOT translate as "it is unknown"\n\u2022 "**Contrary to SOP**" = a procedure violation \u2014 always serious in reports',null,null,null)
B.WM=s(["The accident was caused by an out-of-control aircraft hitting terrain","The aircraft was in controlled flight when it struck terrain","The crew controlled the aircraft into terrain intentionally","The terrain was controlled by ATC when the accident occurred"],t.s)
B.a2A=new A.ab(-300,B.b4,460,'"The accident was attributed to controlled flight into terrain." This means:',B.WM,1,B.A,null,null,null)
B.WB=s(["In accordance with SOPs","Violating or not following SOPs","Similar to SOPs in other companies","An improvement over SOPs"],t.s)
B.a2k=new A.ab(-301,B.b4,461,'"Contrary to standard operating procedures" means:',B.WB,1,B.A,null,null,null)
B.Wu=s(["The main cause was crew rest","Crew rest was one element that made the accident more likely","Crew rest alone caused the accident","The crew rested adequately"],t.s)
B.a2f=new A.ab(-302,B.b4,462,'"A contributing factor was the inadequate crew rest period." This means:',B.Wu,1,B.A,null,null,null)
B.Td=s(["It is confirmed that","There was not enough evidence to establish","It is unlikely that","The investigation did not examine"],t.s)
B.a2_=new A.ab(-303,B.b4,463,'"It could not be determined whether\u2026" in a report means:',B.Td,1,B.aY,null,null,null)
B.Wk=s([B.a2A,B.a2k,B.a2f,B.a2_],t.C)
B.QB=new A.T(B.a4,"Practice Questions",null,null,null,B.Wk)
