B.a2t=new A.ab(-312,B.av,652,"What action permanently eliminates the need for repetitive inspections?",B.Tq,1,B.A,null,null,null)
B.WH=s(["Before the next annual check","Within 100 flight cycles after the effective date","Before the next 500 flight cycles","At first opportunity after receiving the AD"],t.s)
B.a1p=new A.ab(-313,B.av,653,"The first inspection must be completed:",B.WH,1,B.L,null,null,null)
B.UZ=s([B.a1w,B.a1M,B.a2t,B.a1p],t.C)
B.R4=new A.T(B.a4,"Practice Questions",'Read the following AD extract:\n\n"This Airworthiness Directive is applicable to all Airbus A320-200 aircraft, serial numbers 3001 through 5500. The unsafe condition is potential fatigue cracking of the forward fuselage frame. Required action: Perform a detailed visual inspection of the forward fuselage frame assembly. Compliance time: Within 100 flight cycles after the effective date of this AD. Repetitive inspection interval: Every 500 flight cycles thereafter. Terminating action: Replacement of the frame assembly with Part Number A320-FR-9902 permanently terminates the repetitive inspection requirement."',null,null,B.UZ)
